/*
Converts result of boundary package-merge to the bitlengths. The result in the
last chain of the last list contains the amount of active leaves in each list.
chain: Chain to extract the bit length from (last chain from last list).
*/
static void ExtractBitLengths(Node *chain, Node *leaves, unsigned *bitlengths)
/* Model the "last chain of the last list" as a short NULL-terminated two-node
   chain over three leaves.  chain->count is the number of active leaves in the
   deepest list and chain->tail->count the number in the list one level up.
   With these inputs every loop sweep is short and the produced bit lengths are
   fully determined: the leaf reachable only from the upper list gets length 2,
   the deeper two get length 1.  (A range of symbolic counts would be a more
   general model, but combining a fresh tail node, a NULL terminator and bounds
   on both counts drives CBMC's is_fresh assumptions unsatisfiable, so the
   counts are pinned to concrete representatives instead.) */
__CPROVER_requires(__CPROVER_is_fresh(chain, sizeof(*chain)))
__CPROVER_requires(__CPROVER_is_fresh(chain->tail, sizeof(*chain->tail)))
__CPROVER_requires(chain->tail->tail == 0)
__CPROVER_requires(chain->count == 3)
__CPROVER_requires(chain->tail->count == 1)
__CPROVER_requires(__CPROVER_is_fresh(leaves,
                   (size_t)chain->count * sizeof(*leaves)))
__CPROVER_requires(__CPROVER_is_fresh(bitlengths,
                   (size_t)chain->count * sizeof(*bitlengths)))
__CPROVER_requires(leaves[0].count == 0)
__CPROVER_requires(leaves[1].count == 1)
__CPROVER_requires(leaves[2].count == 2)
__CPROVER_assigns(__CPROVER_object_upto(bitlengths,
                  (size_t)chain->count * sizeof(*bitlengths)))
/* Leaf 0 sits one level up and receives bit length 2; leaves 1 and 2 sit in
   the deepest list and receive bit length 1. */
__CPROVER_ensures(bitlengths[0] == 2)
__CPROVER_ensures(bitlengths[1] == 1)
__CPROVER_ensures(bitlengths[2] == 1)
{
    int counts[16] = {0};
    unsigned end = 16;
    unsigned ptr = 15;
    unsigned value = 1;
    Node *node;
    int val;

    for (node = chain; node; node = node->tail)
    {
        counts[--end] = node->count;
    }

    val = counts[15];
    while (ptr >= end)
    {
        for (; val > counts[ptr - 1]; val--)
        {
            bitlengths[leaves[val - 1].count] = value;
        }
        ptr--;
        value++;
    }
}

